// Regex-Tester. Baut RegExp(pattern, flags||g), liefert Treffer mit Index+Gruppen (max 100).
async function run(input) {
  var pattern = String((input && input.pattern) || '');
  var text = String((input && input.text) || '');
  var flags = String((input && input.flags) || 'g');
  if (flags.indexOf('g') < 0) flags += 'g';
  var re;
  try { re = new RegExp(pattern, flags); }
  catch (e) { return { fehler: 'Ungueltiges Pattern: ' + String((e && e.message) || e) }; }
  var matches = [];
  var m;
  var guard = 0;
  while ((m = re.exec(text)) !== null) {
    matches.push({ match: m[0], index: m.index, gruppen: Array.prototype.slice.call(m, 1) });
    if (m.index === re.lastIndex) re.lastIndex++;
    if (matches.length >= 100) break;
    if (++guard > 200000) break;
  }
  return { anzahl: matches.length, treffer: matches };
}
